def validate_redirect_uri(redirect_uri, tenant_config):
    """
    Securely validate the redirect URI against the tenant's allowed configuration.

    SECURITY NOTE: We do NOT use 'if domain in redirect_uri' because that is
    vulnerable to bypass attacks. For example:
      - domain = "example.com"
      - redirect_uri = "https://evil-example.com/callback"  -> would PASS the 'in' check
      - redirect_uri = "https://example.com.attacker.com/callback" -> would PASS the 'in' check
      - redirect_uri = "https://attacker.com/?ref=example.com" -> would PASS the 'in' check

    Instead, we use an exact allowlist of redirect URIs (preferred) and strict
    domain matching as a secondary check.
    """
    if not redirect_uri:
        logger.warning("Empty redirect_uri provided")
        return False

    # Step 1: Exact match against allowlist (most secure approach per OAuth 2.0 spec)
    if redirect_uri in tenant_config.get("allowed_redirect_uris", []):
        return True

    # Step 2: If exact match fails, perform strict domain validation
    # This is a fallback for dynamic paths but still requires strict domain matching
    try:
        parsed = urlparse(redirect_uri)
    except Exception:
        logger.warning("Failed to parse redirect_uri: %s", redirect_uri)
        return False

    # Enforce HTTPS only
    if parsed.scheme != "https":
        logger.warning("Redirect URI must use HTTPS: %s", redirect_uri)
        return False

    # Reject URIs with userinfo (e.g., https://user@attacker.com)
    if parsed.username or parsed.password:
        logger.warning("Redirect URI must not contain userinfo: %s", redirect_uri)
        return False

    # Reject empty or suspicious hostnames
    if not parsed.hostname:
        logger.warning("Redirect URI has no hostname: %s", redirect_uri)
        return False

    # Reject URIs with fragments (not allowed in OAuth 2.0 redirect URIs)
    if parsed.fragment:
        logger.warning("Redirect URI must not contain fragments: %s", redirect_uri)
        return False

    # Strict domain matching - exact hostname match only
    # This prevents attacks like evil-example.com or example.com.attacker.com
    hostname = parsed.hostname.lower()
    allowed_domains = tenant_config.get("allowed_domains", [])

    domain_matched = False
    for allowed_domain in allowed_domains:
        allowed_domain = allowed_domain.lower()
        # Exact match or proper subdomain match (must end with .domain)
        if hostname == allowed_domain or hostname.endswith("." + allowed_domain):
            domain_matched = True
            break

    if not domain_matched:
        logger.warning(
            "Redirect URI hostname '%s' does not match any allowed domain: %s",
            hostname,
            allowed_domains,
        )
        return False

    # Ensure the path is reasonable (no path traversal)
    if ".." in parsed.path:
        logger.warning("Redirect URI contains path traversal: %s", redirect_uri)
        return False

    return True


def get_tenant_config(tenant_id):
    """Retrieve tenant configuration securely."""
    if not tenant_id or not isinstance(tenant_id, str):
        return None
    # Sanitize tenant_id to prevent injection
    tenant_id = tenant_id.strip().lower()
    if not tenant_id.isalnum() and not all(c.isalnum() or c in "-_" for c in tenant_id):
        logger.warning("Invalid tenant_id format: %s", tenant_id)
        return None
    return TENANT_CONFIGS.get(tenant_id)


@app.route("/oauth/authorize/<tenant_id>")
def authorize(tenant_id):
    """Initiate the OAuth 2.0 authorization code flow for a tenant."""
    tenant_config = get_tenant_config(tenant_id)
    if not tenant_config:
        logger.warning("Unknown tenant_id requested: %s", tenant_id)
        abort(404, description="Unknown tenant")

    # Get redirect_uri from query params or use the first allowed URI
    redirect_uri = request.args.get("redirect_uri")
    if not redirect_uri:
        # Default to the first allowed redirect URI
        allowed_uris = tenant_config.get("allowed_redirect_uris", [])
        if not allowed_uris:
            logger.error("No allowed redirect URIs configured for tenant: %s", tenant_id)
            abort(500, description="Misconfigured tenant")
        redirect_uri = allowed_uris[0]

    # Validate the redirect URI securely
    if not validate_redirect_uri(redirect_uri, tenant_config):
        logger.warning(
            "Rejected invalid redirect_uri '%s' for tenant '%s'",
            redirect_uri,
            tenant_id,
        )
        abort(400, description="Invalid redirect_uri")

    # Generate cryptographically secure state parameter to prevent CSRF
    state = secrets.token_urlsafe(32)
    session["oauth_state"] = state
    session["oauth_tenant_id"] = tenant_id
    session["oauth_redirect_uri"] = redirect_uri

    # Generate PKCE code verifier and challenge for additional security
    code_verifier = secrets.token_urlsafe(64)
    session["oauth_code_verifier"] = code_verifier

    import hashlib
    import base64
    code_challenge = base64.urlsafe_b64encode(
        hashlib.sha256(code_verifier.encode("ascii")).digest()
    ).rstrip(b"=").decode("ascii")

    # Build authorization URL
    params = {
        "response_type": "code",
        "client_id": tenant_config["client_id"],
        "redirect_uri": redirect_uri,
        "scope": tenant_config["scopes"],
        "state": state,
        "code_challenge": code_challenge,
        "code_challenge_method": "S256",
    }

    authorization_url = f"{tenant_config['authorization_endpoint']}?{urlencode(params)}"
    logger.info("Initiating OAuth flow for tenant '%s'", tenant_id)
    return redirect(authorization_url)


@app.route("/callback")
def callback():
    """Handle the OAuth 2.0 authorization code callback."""
    # Verify state parameter to prevent CSRF
    state = request.args.get("state")
    stored_state = session.pop("oauth_state", None)

    if not state or not stored_state or not secrets.compare_digest(state, stored_state):
        logger.warning("OAuth callback state mismatch - possible CSRF attack")
        abort(403, description="Invalid state parameter")

    # Check for error response from authorization server
    error = request.args.get("error")
    if error:
        error_description = request.args.get("error_description", "Unknown error")
        logger.warning("OAuth authorization error: %s - %s", error, error_description)
        return jsonify({"error": error, "description": error_description}), 400

    code = request.args.get("code")
    if not code:
        logger.warning("No authorization code in callback")
        abort(400, description="Missing authorization code")

    tenant_id = session.pop("oauth_tenant_id", None)
    redirect_uri = session.pop("oauth_redirect_uri", None)
    code_verifier = session.pop("oauth_code_verifier", None)

    if not tenant_id or not redirect_uri:
        logger.warning("Missing session data in OAuth callback")
        abort(400, description="Invalid session state")

    tenant_config = get_tenant_config(tenant_id)
    if not tenant_config:
        abort(404, description="Unknown tenant")

    # Re-validate redirect_uri from session (defense in depth)
    if not validate_redirect_uri(redirect_uri, tenant_config):
        logger.warning("Stored redirect_uri failed re-validation for tenant '%s'", tenant_id)
        abort(400, description="Invalid redirect_uri")

    # Exchange authorization code for tokens
    token_data = {
        "grant_type": "authorization_code",
        "code": code,
        "redirect_uri": redirect_uri,
        "client_id": tenant_config["client_id"],
        "client_secret": tenant_config["client_secret"],
        "code_verifier": code_verifier,
    }

    try:
        token_response = requests.post(
            tenant_config["token_endpoint"],
            data=token_data,
            headers={"Accept": "application/json"},
            timeout=10,
        )
        token_response.raise_for_status()
        tokens = token_response.json()
    except requests.RequestException as e:
        logger.error("Token exchange failed for tenant '%s': %s", tenant_id, str(e))
        abort(502, description="Token exchange failed")

    # Store tokens securely in session (in production, use encrypted storage)
    # Never log or expose tokens
    session["access_token"] = tokens.get("access_token")
    session["token_type"] = tokens.get("token_type")
    # Don't store refresh tokens in session cookies in production

    logger.info("OAuth flow completed successfully for tenant '%s'", tenant_id)
    return jsonify({
        "status": "authenticated",
        "tenant": tenant_id,
        "token_type": tokens.get("token_type"),
        "scope": tokens.get("scope"),
    })


